export const JS = "\n(function(){\n  var root=document.documentElement;\n  var reduced=root.classList.contains('reduced');\n  function on(el,ev,fn,opts){ el.addEventListener(ev,fn,opts||false); }\n\n  /* ---------- reveal + progress ---------- */\n  (function(){\n    var revs=document.querySelectorAll('.reveal');\n    if(reduced || !('IntersectionObserver' in window)){ revs.forEach(function(e){e.classList.add('in');}); }\n    else { var io=new IntersectionObserver(function(es){ es.forEach(function(e){ if(e.isIntersecting){ e.target.classList.add('in'); io.unobserve(e.target);} }); },{threshold:0.1, rootMargin:'0px 0px -5% 0px'}); revs.forEach(function(e){ io.observe(e); }); }\n    var bar=document.querySelector('.progress');\n    if(bar && !reduced){ on(window,'scroll',function(){ var h=document.documentElement; bar.style.transform='scaleX('+(h.scrollTop/((h.scrollHeight-h.clientHeight)||1))+')'; },{passive:true}); }\n  })();\n\n  /* ---------- audio ---------- */\n  var ARCADE={ active:null, sound:true, ac:null };\n  function audio(){ if(ARCADE.ac) return ARCADE.ac; try{ ARCADE.ac=new (window.AudioContext||window.webkitAudioContext)(); }catch(e){} return ARCADE.ac; }\n  function beep(freq,dur,type,vol){ if(!ARCADE.sound) return; var ac=audio(); if(!ac) return; try{ if(ac.state==='suspended') ac.resume(); var o=ac.createOscillator(), g=ac.createGain(); o.type=type||'square'; o.frequency.value=freq; var v=(vol||0.035); g.gain.value=v; o.connect(g); g.connect(ac.destination); var t=ac.currentTime; o.start(t); g.gain.setValueAtTime(v,t); g.gain.exponentialRampToValueAtTime(0.0001, t+(dur||0.08)); o.stop(t+(dur||0.08)+0.02);}catch(e){} }\n  (function(){\n    var b=document.getElementById('sound-btn'), st=document.getElementById('sound-state');\n    function tog(){ ARCADE.sound=!ARCADE.sound; st.textContent=ARCADE.sound?'AÇIK':'KAPALI'; if(ARCADE.sound) beep(880,0.06); }\n    on(b,'click',tog); on(b,'keydown',function(e){ if(e.key==='Enter'||e.key===' '){ e.preventDefault(); tog(); } });\n  })();\n\n  /* ---------- input helpers ---------- */\n  function holdBtn(el, press, release){\n    if(!el) return;\n    var down=function(e){ if(e.cancelable) e.preventDefault(); el.classList.add('on'); press(); };\n    var up=function(e){ if(e&&e.cancelable) e.preventDefault(); el.classList.remove('on'); release(); };\n    on(el,'touchstart',down,{passive:false}); on(el,'touchend',up); on(el,'touchcancel',up);\n    on(el,'mousedown',down); on(window,'mouseup',up); on(el,'mouseleave',function(){ if(el.classList.contains('on')){ el.classList.remove('on'); release(); } });\n  }\n  function tapBtn(el, fn){\n    if(!el) return;\n    var f=function(e){ if(e.cancelable) e.preventDefault(); el.classList.add('on'); setTimeout(function(){el.classList.remove('on');},90); fn(); };\n    on(el,'touchstart',f,{passive:false}); on(el,'mousedown',f);\n  }\n  function setActive(cab,id){ on(cab,'pointerdown',function(){ ARCADE.active=id; }); }\n\n  function runLoop(step){\n    var raf=null, last=0, running=false;\n    function frame(ts){ if(!running) return; if(!last) last=ts; var dt=ts-last; last=ts; if(dt>50) dt=50; step(dt/16.6667); raf=requestAnimationFrame(frame); }\n    return {\n      start:function(){ if(running) return; running=true; last=0; raf=requestAnimationFrame(frame); },\n      stop:function(){ running=false; if(raf) cancelAnimationFrame(raf); raf=null; }\n    };\n  }\n  function visObserver(el, loop){\n    if(!('IntersectionObserver' in window)){ loop.start(); return; }\n    var io=new IntersectionObserver(function(es){ es.forEach(function(e){ if(e.isIntersecting) loop.start(); else loop.stop(); }); },{threshold:0.05});\n    io.observe(el);\n  }\n\n  /* =====================================================\n     PONG  (oscilloscope, green phosphor)\n  ===================================================== */\n  (function(){\n    var ID='pong', cv=document.getElementById('pong'); if(!cv) return;\n    var ctx=cv.getContext('2d'), W=cv.width, H=cv.height; ctx.imageSmoothingEnabled=false;\n    var PH=54, PW=7, LX=14, RX=W-14-PW, TARGET=5;\n    var P={y:H/2-PH/2}, A={y:H/2-PH/2}, ball={x:W/2,y:H/2,vx:0,vy:0,sp:3,r:4};\n    var sL=0,sR=0, started=false, over=false, msg='', up=false, down=false, dragY=null, t=0;\n\n    function serve(left){ ball.x=W/2; ball.y=H/2; ball.sp=3; var a=(Math.random()*0.7-0.35); ball.vx=(left?-1:1)*ball.sp*Math.cos(a); ball.vy=ball.sp*Math.sin(a); }\n    function newGame(){ sL=0;sR=0;over=false;msg='';P.y=A.y=H/2-PH/2; serve(Math.random()<0.5); started=true; }\n\n    function key(e,d){ if(ARCADE.active!==ID) return; var k=e.key;\n      if(k==='ArrowUp'||k==='w'||k==='W'){ up=d; e.preventDefault(); }\n      else if(k==='ArrowDown'||k==='s'||k==='S'){ down=d; e.preventDefault(); }\n      else if(d && (k===' '||k==='Enter')){ if(!started||over) newGame(); e.preventDefault(); } }\n    on(window,'keydown',function(e){key(e,true);}); on(window,'keyup',function(e){key(e,false);});\n\n    function py(e){ var r=cv.getBoundingClientRect(); var cy=(e.touches?e.touches[0].clientY:e.clientY)-r.top; return cy*(H/r.height); }\n    function pd(e){ ARCADE.active=ID; if(!started||over) newGame(); dragY=py(e); if(e.cancelable)e.preventDefault(); }\n    function pm(e){ if(dragY!==null){ dragY=py(e); if(e.cancelable)e.preventDefault(); } }\n    function pu(){ dragY=null; }\n    on(cv,'mousedown',pd); on(window,'mousemove',pm); on(window,'mouseup',pu);\n    on(cv,'touchstart',pd,{passive:false}); on(cv,'touchmove',pm,{passive:false}); on(cv,'touchend',pu);\n    holdBtn(document.getElementById('pong-up'), function(){ ARCADE.active=ID; if(!started||over)newGame(); up=true; }, function(){ up=false; });\n    holdBtn(document.getElementById('pong-down'), function(){ ARCADE.active=ID; if(!started||over)newGame(); down=true; }, function(){ down=false; });\n\n    function update(s){\n      if(!started||over) return;\n      if(dragY!==null) P.y += (((dragY)-PH/2)-P.y)*0.45;\n      if(up) P.y-=4.2*s; if(down) P.y+=4.2*s;\n      P.y=Math.max(0,Math.min(H-PH,P.y));\n      var ac=A.y+PH/2, diff=ball.y-ac, asp=3.3*s;\n      if(ball.vx>0){ if(Math.abs(diff)>5) A.y += (diff>0?1:-1)*Math.min(asp,Math.abs(diff)); }\n      else { var hc=H/2-PH/2; A.y += (hc-A.y)*0.02; }\n      A.y=Math.max(0,Math.min(H-PH,A.y));\n      ball.x+=ball.vx*s; ball.y+=ball.vy*s;\n      if(ball.y<ball.r){ ball.y=ball.r; ball.vy=-ball.vy; beep(200,0.02,'square',0.02); }\n      if(ball.y>H-ball.r){ ball.y=H-ball.r; ball.vy=-ball.vy; beep(200,0.02,'square',0.02); }\n      if(ball.vx<0 && ball.x-ball.r<=LX+PW && ball.x-ball.r>LX-6 && ball.y>P.y && ball.y<P.y+PH){\n        ball.x=LX+PW+ball.r; var rel=(ball.y-(P.y+PH/2))/(PH/2); ball.sp=Math.min(ball.sp+0.35,7.5); var a=rel*0.9;\n        ball.vx=Math.abs(ball.sp*Math.cos(a)); ball.vy=ball.sp*Math.sin(a); beep(480,0.03,'square',0.03); }\n      if(ball.vx>0 && ball.x+ball.r>=RX && ball.x+ball.r<RX+PW+6 && ball.y>A.y && ball.y<A.y+PH){\n        ball.x=RX-ball.r; var rel2=(ball.y-(A.y+PH/2))/(PH/2); ball.sp=Math.min(ball.sp+0.35,7.5); var a2=rel2*0.9;\n        ball.vx=-Math.abs(ball.sp*Math.cos(a2)); ball.vy=ball.sp*Math.sin(a2); beep(480,0.03,'square',0.03); }\n      if(ball.x<-2){ sR++; beep(120,0.14,'sawtooth',0.04); if(sR>=TARGET){over=true;msg='GAME OVER';} else serve(false); }\n      else if(ball.x>W+2){ sL++; beep(720,0.1,'square',0.04); if(sL>=TARGET){over=true;msg='YOU WIN!';} else serve(true); }\n    }\n\n    function txt(s,x,y,size,col){ ctx.fillStyle=col; ctx.font='bold '+size+'px monospace'; ctx.textAlign='center'; ctx.fillText(s,x,y); }\n    function draw(){\n      ctx.fillStyle='rgba(1,12,6,0.38)'; ctx.fillRect(0,0,W,H);\n      ctx.save(); ctx.shadowColor='#36ff9e'; ctx.shadowBlur=7; ctx.fillStyle='#36ff9e';\n      for(var i=8;i<H;i+=22){ ctx.fillRect(W/2-1,i,2,11); }\n      ctx.fillRect(LX,P.y,PW,PH); ctx.fillRect(RX,A.y,PW,PH);\n      ctx.beginPath(); ctx.arc(ball.x,ball.y,ball.r,0,7); ctx.fill();\n      txt(sL, W/2-40, 26, 18, '#36ff9e'); txt(sR, W/2+40, 26, 18, '#36ff9e');\n      ctx.restore();\n      if(!started){ txt('PRESS START', W/2, H/2-6, 13, '#9dffd0'); txt('dokun / tıkla', W/2, H/2+14, 9, '#3fae7e'); }\n      else if(over){ txt(msg, W/2, H/2-4, 14, msg==='YOU WIN!'?'#ffd23f':'#ff5a6e'); txt('tekrar için dokun', W/2, H/2+16, 9, '#9dffd0'); }\n    }\n    var loop=runLoop(function(s){ update(s); draw(); });\n    var cab=cv.closest('.cab'); setActive(cab,ID); draw(); visObserver(cab, loop);\n  })();\n\n  /* =====================================================\n     PAC-MAN\n  ===================================================== */\n  (function(){\n    var ID='pac', cv=document.getElementById('pac'); if(!cv) return;\n    var ctx=cv.getContext('2d'); ctx.imageSmoothingEnabled=false;\n    var COLS=15, ROWS=15, TS=18; cv.width=COLS*TS; cv.height=ROWS*TS;\n    var scoreEl=document.getElementById('pac-score'), livesEl=document.getElementById('pac-lives');\n    var maze, dots, pac, ghosts, score, lives, started, over, won, dead, deadT;\n    var CC=(COLS-1)/2, CR=(ROWS-1)/2;\n\n    function build(){\n      maze=[]; dots=0;\n      for(var r=0;r<ROWS;r++){ var row=[]; for(var c=0;c<COLS;c++){\n        if(r===0||c===0||r===ROWS-1||c===COLS-1) row.push('#');\n        else if(r%2===0 && c%2===0) row.push('#');\n        else row.push('.');\n      } maze.push(row); }\n      maze[1][1]='o'; maze[1][COLS-2]='o'; maze[ROWS-2][1]='o'; maze[ROWS-2][COLS-2]='o';\n      [[CR,CC],[CR-1,CC],[CR+1,CC],[CR,CC-1],[CR,CC+1]].forEach(function(p){ if(maze[p[0]][p[1]]!=='#') maze[p[0]][p[1]]=' '; });\n      for(var rr=0;rr<ROWS;rr++)for(var cc=0;cc<COLS;cc++){ if(maze[rr][cc]==='.'||maze[rr][cc]==='o') dots++; }\n    }\n    function open(r,c){ return r>=0&&r<ROWS&&c>=0&&c<COLS&&maze[r][c]!=='#'; }\n\n    function resetActors(){\n      pac={ r:ROWS-2, c:CC, dir:[0,0], want:[0,0], moving:false, t:0, mouth:0 };\n      ghosts=[\n        { r:CR, c:CC, color:'#ff5a6e', dir:[0,-1], want:[0,-1], moving:false, t:0, fright:0, jitter:0.4 },\n        { r:CR, c:CC-1, color:'#5ad6ff', dir:[0,-1], want:[0,-1], moving:false, t:0, fright:0, jitter:1.6 },\n        { r:CR, c:CC+1, color:'#ffb86b', dir:[0,-1], want:[0,-1], moving:false, t:0, fright:0, jitter:3.0 }\n      ];\n    }\n    function newGame(){ build(); resetActors(); score=0; lives=3; over=false; won=false; dead=false; deadT=0; started=true; sync(); }\n    function sync(){ if(scoreEl)scoreEl.textContent=score; if(livesEl)livesEl.textContent=lives; }\n\n    function setWant(dx,dy){ if(!started||over){ newGame(); } ARCADE.active=ID; pac.want=[dx,dy]; }\n    function key(e){ if(ARCADE.active!==ID) return; var k=e.key, h=false;\n      if(k==='ArrowUp'||k==='w'||k==='W'){ setWant(0,-1); h=true; }\n      else if(k==='ArrowDown'||k==='s'||k==='S'){ setWant(0,1); h=true; }\n      else if(k==='ArrowLeft'||k==='a'||k==='A'){ setWant(-1,0); h=true; }\n      else if(k==='ArrowRight'||k==='d'||k==='D'){ setWant(1,0); h=true; }\n      else if(k===' '||k==='Enter'){ if(!started||over) newGame(); h=true; }\n      if(h) e.preventDefault(); }\n    on(window,'keydown',key);\n    tapBtn(document.getElementById('pac-up'), function(){ setWant(0,-1); });\n    tapBtn(document.getElementById('pac-down'), function(){ setWant(0,1); });\n    tapBtn(document.getElementById('pac-left'), function(){ setWant(-1,0); });\n    tapBtn(document.getElementById('pac-right'), function(){ setWant(1,0); });\n\n    function startStep(e){\n      var d=null;\n      if((e.want[0]||e.want[1]) && open(e.r+e.want[1], e.c+e.want[0])) d=e.want;\n      else if((e.dir[0]||e.dir[1]) && open(e.r+e.dir[1], e.c+e.dir[0])) d=e.dir;\n      if(d){ e.dir=d; e.moving=true; e.t=0; e.tr=e.r+d[1]; e.tc=e.c+d[0]; } else { e.moving=false; }\n    }\n    function ghostThink(g){\n      var dirs=[[1,0],[-1,0],[0,1],[0,-1]], opts=[];\n      dirs.forEach(function(d){ if(d[0]===-g.dir[0]&&d[1]===-g.dir[1]) return; if(open(g.r+d[1],g.c+d[0])) opts.push(d); });\n      if(!opts.length) opts.push([-g.dir[0],-g.dir[1]]);\n      var pick=opts[0];\n      if(g.fright>0){ pick=opts[(Math.random()*opts.length)|0]; }\n      else { var best=1e9; opts.forEach(function(d){ var nr=g.r+d[1], nc=g.c+d[0]; var dist=(nr-pac.r)*(nr-pac.r)+(nc-pac.c)*(nc-pac.c)+Math.random()*g.jitter; if(dist<best){ best=dist; pick=d; } }); }\n      g.want=pick;\n    }\n    function pix(e){ var x0=e.c*TS+TS/2, y0=e.r*TS+TS/2; if(e.moving){ var x1=e.tc*TS+TS/2, y1=e.tr*TS+TS/2; return [x0+(x1-x0)*e.t, y0+(y1-y0)*e.t]; } return [x0,y0]; }\n\n    function eat(){ var ch=maze[pac.r][pac.c];\n      if(ch==='.'){ maze[pac.r][pac.c]=' '; score+=10; dots--; beep(560,0.018,'square',0.02); sync(); }\n      else if(ch==='o'){ maze[pac.r][pac.c]=' '; score+=50; dots--; ghosts.forEach(function(g){ g.fright=380; }); beep(160,0.18,'square',0.04); sync(); }\n      if(dots<=0){ won=true; over=true; beep(880,0.5,'square',0.05); }\n    }\n\n    function update(s){\n      if(!started||over) return;\n      if(dead){ deadT-=s; if(deadT<=0){ dead=false; resetActors(); } return; }\n      pac.mouth+=0.25*s;\n      // pac move\n      if(!pac.moving) startStep(pac);\n      if(pac.moving){ pac.t+=0.16*s; if(pac.t>=1){ pac.r=pac.tr; pac.c=pac.tc; pac.t=0; pac.moving=false; eat(); startStep(pac); } }\n      // ghosts\n      ghosts.forEach(function(g){\n        var sp = g.fright>0 ? 0.075 : 0.115;\n        if(g.fright>0) g.fright-=s;\n        if(!g.moving){ ghostThink(g); startStep2(g); }\n        if(g.moving){ g.t+=sp*s; if(g.t>=1){ g.r=g.tr; g.c=g.tc; g.t=0; g.moving=false; } }\n      });\n      // collisions\n      var pp=pix(pac);\n      for(var i=0;i<ghosts.length;i++){ var g=ghosts[i], gp=pix(g); var dx=pp[0]-gp[0], dy=pp[1]-gp[1];\n        if(dx*dx+dy*dy < (TS*0.62)*(TS*0.62)){\n          if(g.fright>0){ score+=200; beep(990,0.12,'square',0.05); g.r=CR; g.c=CC; g.dir=[0,-1]; g.want=[0,-1]; g.moving=false; g.t=0; g.fright=0; sync(); }\n          else { lives--; beep(110,0.4,'sawtooth',0.05); sync(); if(lives<=0){ over=true; won=false; } else { dead=true; deadT=60; } return; }\n        } }\n    }\n    function startStep2(g){ // ghost uses want from think\n      if(open(g.r+g.want[1], g.c+g.want[0])){ g.dir=g.want; g.moving=true; g.t=0; g.tr=g.r+g.want[1]; g.tc=g.c+g.want[0]; }\n      else g.moving=false;\n    }\n\n    function draw(){\n      ctx.fillStyle='#000'; ctx.fillRect(0,0,cv.width,cv.height);\n      // walls\n      for(var r=0;r<ROWS;r++)for(var c=0;c<COLS;c++){ var ch=maze[r][c];\n        if(ch==='#'){ ctx.fillStyle='#1c2bff'; roundRect(c*TS+2,r*TS+2,TS-4,TS-4,4); ctx.fill(); ctx.fillStyle='#3a48ff'; roundRect(c*TS+4,r*TS+4,TS-8,TS-8,3); ctx.fill(); }\n        else if(ch==='.'){ ctx.fillStyle='#ffd6a8'; ctx.beginPath(); ctx.arc(c*TS+TS/2,r*TS+TS/2,2,0,7); ctx.fill(); }\n        else if(ch==='o'){ var pr=4+Math.sin(Date.now()/180)*1.2; ctx.fillStyle='#ffe14d'; ctx.beginPath(); ctx.arc(c*TS+TS/2,r*TS+TS/2,pr,0,7); ctx.fill(); }\n      }\n      // pac\n      var pp=pix(pac), ang=Math.atan2(pac.dir[1],pac.dir[0]); if(pac.dir[0]===0&&pac.dir[1]===0) ang=0;\n      var m=(Math.sin(pac.mouth)*0.5+0.5)*0.32+0.02;\n      ctx.fillStyle='#ffe14d'; ctx.beginPath(); ctx.moveTo(pp[0],pp[1]);\n      ctx.arc(pp[0],pp[1],TS/2-1, ang+m*Math.PI, ang+(2-m)*Math.PI); ctx.closePath(); ctx.fill();\n      // ghosts\n      ghosts.forEach(function(g){ var gp=pix(g); drawGhost(gp[0],gp[1],TS/2-1,g); });\n      if(!started){ banner('PRESS START','dokun / tıkla','#ffe14d'); }\n      else if(over){ banner(won?'KAZANDIN!':'GAME OVER','tekrar için dokun', won?'#36ff9e':'#ff5a6e'); }\n    }\n    function drawGhost(x,y,rad,g){\n      var body = g.fright>0 ? ((g.fright<110 && (Math.floor(g.fright/12)%2===0))?'#fff':'#2a4bff') : g.color;\n      ctx.fillStyle=body; ctx.beginPath(); ctx.arc(x,y-1,rad,Math.PI,0); ctx.lineTo(x+rad,y+rad);\n      for(var i=0;i<3;i++){ ctx.lineTo(x+rad-(i*2+1)*rad/3, y+rad-((i%2)?0:rad*0.5)); }\n      ctx.lineTo(x-rad,y+rad); ctx.closePath(); ctx.fill();\n      if(g.fright>0){ ctx.fillStyle=(body==='#fff')?'#ff5a6e':'#fff'; ctx.fillRect(x-3,y-2,2,3); ctx.fillRect(x+1,y-2,2,3); }\n      else { ctx.fillStyle='#fff'; ctx.beginPath(); ctx.arc(x-3,y-1,2.4,0,7); ctx.arc(x+3,y-1,2.4,0,7); ctx.fill();\n        ctx.fillStyle='#1133ff'; ctx.beginPath(); ctx.arc(x-3+g.dir[0]*1.2,y-1+g.dir[1]*1.2,1.2,0,7); ctx.arc(x+3+g.dir[0]*1.2,y-1+g.dir[1]*1.2,1.2,0,7); ctx.fill(); }\n    }\n    function roundRect(x,y,w,h,r){ ctx.beginPath(); ctx.moveTo(x+r,y); ctx.arcTo(x+w,y,x+w,y+h,r); ctx.arcTo(x+w,y+h,x,y+h,r); ctx.arcTo(x,y+h,x,y,r); ctx.arcTo(x,y,x+w,y,r); ctx.closePath(); }\n    function banner(a,b,col){ ctx.fillStyle='rgba(0,0,0,0.7)'; ctx.fillRect(0,cv.height/2-26,cv.width,52); ctx.textAlign='center';\n      ctx.fillStyle=col; ctx.font='bold 16px monospace'; ctx.fillText(a,cv.width/2,cv.height/2-2);\n      ctx.fillStyle='#cbbdf0'; ctx.font='9px monospace'; ctx.fillText(b,cv.width/2,cv.height/2+15); }\n\n    build(); resetActors(); score=0; lives=3; started=false; over=false; won=false; dead=false;\n    var loop=runLoop(function(s){ update(s); draw(); });\n    var cab=cv.closest('.cab'); setActive(cab,ID); draw(); visObserver(cab, loop);\n  })();\n\n  /* =====================================================\n     MARIO  (platformer)\n  ===================================================== */\n  (function(){\n    var ID='mario', cv=document.getElementById('mario'); if(!cv) return;\n    var ctx=cv.getContext('2d'); ctx.imageSmoothingEnabled=false;\n    var VW=cv.width, VH=cv.height, LW=1180, GY=VH-22;\n    var scoreEl=document.getElementById('mario-score'), livesEl=document.getElementById('mario-lives');\n    var plats=[\n      {x:0,y:GY,w:360,h:30},{x:420,y:GY,w:760,h:30}, // ground with a pit (360-420)\n      {x:150,y:VH-66,w:60,h:10},{x:250,y:VH-100,w:60,h:10},\n      {x:470,y:VH-70,w:54,h:10},{x:560,y:VH-104,w:54,h:10},{x:660,y:VH-70,w:60,h:10},\n      {x:820,y:VH-80,w:60,h:10},{x:930,y:VH-112,w:60,h:10},{x:1030,y:VH-72,w:70,h:10}\n    ];\n    var coins=[{x:170,y:VH-86},{x:270,y:VH-120},{x:485,y:VH-90},{x:575,y:VH-124},{x:675,y:VH-90},{x:845,y:VH-100},{x:955,y:VH-132},{x:500,y:VH-44},{x:700,y:VH-44},{x:1045,y:VH-92}];\n    var P, enemies, cam, score, lives, started, over, won, left, right, jump, jHeld;\n    function spawn(){ P={x:30,y:GY-22,w:14,h:20,vx:0,vy:0,ground:false,face:1,walk:0}; cam=0; }\n    function reset(){ spawn(); enemies=[ {x:520,y:GY-16,w:16,h:16,vx:0.5,min:430,max:700,alive:true}, {x:980,y:GY-16,w:16,h:16,vx:0.6,min:900,max:1100,alive:true} ];\n      coins.forEach(function(c){ c.t=false; }); }\n    function newGame(){ reset(); score=0; lives=3; over=false; won=false; started=true; sync(); }\n    function sync(){ if(scoreEl)scoreEl.textContent=score; if(livesEl)livesEl.textContent=lives; }\n\n    function key(e,d){ if(ARCADE.active!==ID) return; var k=e.key, h=false;\n      if(k==='ArrowLeft'||k==='a'||k==='A'){ left=d; h=true; }\n      else if(k==='ArrowRight'||k==='d'||k==='D'){ right=d; h=true; }\n      else if(k===' '||k==='ArrowUp'||k==='w'||k==='W'){ if(d&&!jHeld){ jump=true; } jHeld=d; h=true; if(d&&(!started||over)) newGame(); }\n      else if(d && k==='Enter'){ if(!started||over) newGame(); h=true; }\n      if(h) e.preventDefault(); }\n    on(window,'keydown',function(e){key(e,true);}); on(window,'keyup',function(e){key(e,false);});\n    holdBtn(document.getElementById('mario-left'), function(){ ARCADE.active=ID; if(!started||over)newGame(); left=true; }, function(){ left=false; });\n    holdBtn(document.getElementById('mario-right'), function(){ ARCADE.active=ID; if(!started||over)newGame(); right=true; }, function(){ right=false; });\n    holdBtn(document.getElementById('mario-jump'), function(){ ARCADE.active=ID; if(!started||over){ newGame(); return; } if(!jHeld) jump=true; jHeld=true; }, function(){ jHeld=false; });\n\n    function hit(a,b){ return a.x<b.x+b.w && a.x+a.w>b.x && a.y<b.y+b.h && a.y+a.h>b.y; }\n\n    function update(s){\n      if(!started||over) return;\n      var ac=0.55, mx=2.6, fr=0.78;\n      if(left){ P.vx-=ac*s; P.face=-1; } if(right){ P.vx+=ac*s; P.face=1; }\n      if(!left&&!right){ P.vx*=Math.pow(fr, s); if(Math.abs(P.vx)<0.05) P.vx=0; }\n      P.vx=Math.max(-mx,Math.min(mx,P.vx));\n      if(jump && P.ground){ P.vy=-9.4; P.ground=false; beep(660,0.07,'square',0.035); }\n      jump=false;\n      P.vy+=0.5*s; if(P.vy>11) P.vy=11;\n      // horizontal\n      P.x+=P.vx*s;\n      for(var i=0;i<plats.length;i++){ var pl=plats[i]; if(hit(P,pl)){ if(P.vx>0){ P.x=pl.x-P.w; } else if(P.vx<0){ P.x=pl.x+pl.w; } P.vx=0; } }\n      if(P.x<0) P.x=0;\n      // vertical\n      P.y+=P.vy*s; P.ground=false;\n      for(var j=0;j<plats.length;j++){ var p2=plats[j]; if(hit(P,p2)){ if(P.vy>0){ P.y=p2.y-P.h; P.vy=0; P.ground=true; } else if(P.vy<0){ P.y=p2.y+p2.h; P.vy=0; } } }\n      if(P.vx!==0 && P.ground) P.walk+=Math.abs(P.vx)*0.12*s; \n      // fall in pit\n      if(P.y>VH+40){ loseLife(); return; }\n      // enemies\n      enemies.forEach(function(en){ if(!en.alive) return; en.x+=en.vx*s; if(en.x<en.min){ en.x=en.min; en.vx=Math.abs(en.vx); } if(en.x+en.w>en.max){ en.x=en.max-en.w; en.vx=-Math.abs(en.vx); }\n        if(hit(P,en)){ if(P.vy>0 && P.y+P.h-en.y<10){ en.alive=false; P.vy=-6; score+=100; beep(880,0.08,'square',0.04); sync(); } else { loseLife(); } } });\n      // coins\n      coins.forEach(function(c){ if(c.t) return; if(P.x<c.x+8 && P.x+P.w>c.x-8 && P.y<c.y+8 && P.y+P.h>c.y-8){ c.t=true; score+=50; beep(1040,0.06,'square',0.035); sync(); } });\n      // goal\n      if(P.x+P.w > LW-24){ won=true; over=true; beep(523,0.12,'square',0.05); setTimeout(function(){beep(784,0.18,'square',0.05);},120); }\n      // camera\n      cam=Math.max(0, Math.min(LW-VW, P.x+P.w/2-VW/2));\n    }\n    function loseLife(){ lives--; beep(140,0.3,'sawtooth',0.05); sync(); if(lives<=0){ over=true; won=false; } else { spawn(); } }\n\n    function draw(){\n      // sky\n      var g=ctx.createLinearGradient(0,0,0,VH); g.addColorStop(0,'#1a1140'); g.addColorStop(1,'#3a1d5e'); ctx.fillStyle=g; ctx.fillRect(0,0,VW,VH);\n      // parallax hills + clouds\n      ctx.fillStyle='rgba(120,80,200,0.35)'; for(var h=0;h<4;h++){ var hx=(h*420 - cam*0.4)%(LW); if(hx<-260)hx+=LW; ctx.beginPath(); ctx.arc(hx,VH-18,90,Math.PI,0); ctx.fill(); }\n      ctx.fillStyle='rgba(255,255,255,0.18)'; for(var k=0;k<4;k++){ var cx=(k*360+60 - cam*0.5); cx=((cx%LW)+LW)%LW; cloud(cx, 28+ (k%2)*16); }\n      ctx.save(); ctx.translate(-cam,0);\n      // platforms\n      plats.forEach(function(pl){ var top=pl.y; ctx.fillStyle='#6b3f1d'; ctx.fillRect(pl.x,top,pl.w,pl.h);\n        ctx.fillStyle='#46e36b'; ctx.fillRect(pl.x,top,pl.w,4);\n        ctx.strokeStyle='rgba(0,0,0,0.25)'; for(var bx=pl.x;bx<pl.x+pl.w;bx+=16){ ctx.strokeRect(bx,top+4,16,pl.h-4); } });\n      // coins\n      coins.forEach(function(c){ if(c.t) return; var sw=Math.abs(Math.sin(Date.now()/200+c.x)); ctx.fillStyle='#ffd23f'; ctx.beginPath(); ctx.ellipse(c.x,c.y,5*sw+1.5,6,0,0,7); ctx.fill(); ctx.fillStyle='#b8860b'; ctx.fillRect(c.x-1,c.y-3,2,6); });\n      // goal flag\n      ctx.fillStyle='#ddd'; ctx.fillRect(LW-22,VH-90,3,68); ctx.fillStyle='#ff2e88'; ctx.beginPath(); ctx.moveTo(LW-19,VH-90); ctx.lineTo(LW-19,VH-72); ctx.lineTo(LW-2,VH-81); ctx.closePath(); ctx.fill();\n      // enemies\n      enemies.forEach(function(en){ if(!en.alive) return; ctx.fillStyle='#9b4d2a'; roundR(en.x,en.y,en.w,en.h,4); ctx.fill();\n        ctx.fillStyle='#fff'; ctx.fillRect(en.x+3,en.y+4,3,4); ctx.fillRect(en.x+10,en.y+4,3,4); ctx.fillStyle='#000'; ctx.fillRect(en.x+4,en.y+5,1.5,2); ctx.fillRect(en.x+11,en.y+5,1.5,2);\n        ctx.fillStyle='#3a1c10'; ctx.fillRect(en.x+2,en.y+en.h,3,2); ctx.fillRect(en.x+en.w-5,en.y+en.h,3,2); });\n      // player (generic plumber)\n      drawHero(P.x,P.y,P.w,P.h,P.face,P.ground,P.walk);\n      ctx.restore();\n      if(!started){ banner('PRESS START','dokun / tıkla','#ffd23f'); }\n      else if(over){ banner(won?'LEVEL CLEAR!':'GAME OVER','tekrar için dokun', won?'#36ff9e':'#ff5a6e'); }\n    }\n    function cloud(x,y){ ctx.beginPath(); ctx.arc(x,y,10,0,7); ctx.arc(x+12,y+2,13,0,7); ctx.arc(x+26,y,10,0,7); ctx.fill(); }\n    function roundR(x,y,w,h,r){ ctx.beginPath(); ctx.moveTo(x+r,y); ctx.arcTo(x+w,y,x+w,y+h,r); ctx.arcTo(x+w,y+h,x,y+h,r); ctx.arcTo(x,y+h,x,y,r); ctx.arcTo(x,y,x+w,y,r); ctx.closePath(); }\n    function drawHero(x,y,w,h,face,ground,walk){\n      ctx.save(); ctx.translate(x,y);\n      ctx.fillStyle='#3a6bff'; ctx.fillRect(2,h-10,w-4,10);            // overalls\n      ctx.fillStyle='#ff3b3b'; ctx.fillRect(1,5,w-2,h-12);            // shirt\n      ctx.fillStyle='#ffd2a6'; ctx.fillRect(2,3,w-4,5);              // face\n      ctx.fillStyle='#ff3b3b'; ctx.fillRect(0,0,w,4);                // cap\n      ctx.fillStyle='#000'; ctx.fillRect(face>0?w-5:2,4,2,2);        // eye\n      var step = ground ? (Math.floor(walk)%2) : 0;                  // legs\n      ctx.fillStyle='#2a1a0a'; ctx.fillRect(2+step*2,h-2,4,2); ctx.fillRect(w-6-step*2,h-2,4,2);\n      ctx.restore();\n    }\n    function banner(a,b,col){ ctx.fillStyle='rgba(0,0,0,0.65)'; ctx.fillRect(0,VH/2-24,VW,48); ctx.textAlign='center';\n      ctx.fillStyle=col; ctx.font='bold 15px monospace'; ctx.fillText(a,VW/2,VH/2-1); ctx.fillStyle='#cbbdf0'; ctx.font='9px monospace'; ctx.fillText(b,VW/2,VH/2+15); }\n\n    spawn(); enemies=[]; reset(); score=0; lives=3; started=false; over=false; won=false;\n    var loop=runLoop(function(s){ update(s); draw(); });\n    var cab=cv.closest('.cab'); setActive(cab,ID); draw(); visObserver(cab, loop);\n  })();\n\n  /* =====================================================\n     KONAMI CODE easter egg\n  ===================================================== */\n  (function(){\n    var seq=['ArrowUp','ArrowUp','ArrowDown','ArrowDown','ArrowLeft','ArrowRight','ArrowLeft','ArrowRight','b','a'];\n    var pos=0;\n    var toast=document.getElementById('konami');\n    var cv=document.getElementById('confetti');\n    var ctx=null, parts=[], running=false;\n    on(window,'keydown',function(e){\n      var k=e.key.length===1?e.key.toLowerCase():e.key;\n      if(k===seq[pos]){ pos++; if(pos===seq.length){ pos=0; party(); } }\n      else { pos=(k===seq[0])?1:0; }\n    });\n    function party(){\n      beep(523,0.1,'square',0.05); setTimeout(function(){beep(659,0.1,'square',0.05);},110); setTimeout(function(){beep(784,0.16,'square',0.05);},230);\n      if(toast){ toast.style.display='block'; toast.style.transform='translate(-50%,-50%) scale(1)'; setTimeout(function(){ toast.style.display='none'; },2600); }\n      if(reduced || !cv) return;\n      cv.style.display='block'; cv.width=window.innerWidth; cv.height=window.innerHeight; ctx=cv.getContext('2d');\n      var cols=['#ff2e88','#2ce6e6','#ffd23f','#36ff9e','#a274ff'];\n      parts=[];\n      for(var i=0;i<140;i++){ parts.push({ x:Math.random()*cv.width, y:-20-Math.random()*cv.height*0.4, s:4+Math.random()*5, vy:2+Math.random()*3.4, vx:(Math.random()-0.5)*2, c:cols[(Math.random()*cols.length)|0], rot:Math.random()*6, vr:(Math.random()-0.5)*0.3 }); }\n      if(!running){ running=true; requestAnimationFrame(loop); }\n    }\n    function loop(){\n      if(!running) return;\n      ctx.clearRect(0,0,cv.width,cv.height);\n      var alive=false;\n      parts.forEach(function(p){ p.y+=p.vy; p.x+=p.vx; p.rot+=p.vr; if(p.y<cv.height+20) alive=true; ctx.save(); ctx.translate(p.x,p.y); ctx.rotate(p.rot); ctx.fillStyle=p.c; ctx.fillRect(-p.s/2,-p.s/2,p.s,p.s); ctx.restore(); });\n      if(alive){ requestAnimationFrame(loop); } else { running=false; cv.style.display='none'; }\n    }\n  })();\n\n})();\n";
